// Neon Wash — gradient blended with osc, full-screen color sweeps
speed = 0.5

AUDIO.bins = 6; AUDIO.smooth = 0.78; AUDIO.gain = 50; AUDIO.apply();
var _lo = function(){ return a.fft[0] || 0 };
var _mi = function(){ return a.fft[2] || 0 };
var _hi = function(){ return a.fft[4] || 0 };
var low  = env(_lo, 0.4, 0.03);
var mid  = env(_mi, 0.35, 0.04);
var high = env(_hi, 0.3, 0.05);
var amp  = function(){ return (low() + mid() + high()) * 0.7 };

// gradient base with slow rotation = sweeping color field
gradient(0.15)
  .rotate(() => time * 0.02)
  .saturate(2)
  .color(
    () => 0.6 + low() * 1.2,
    () => 0.4 + mid() * 0.8,
    () => 0.8 + high() * 0.7
  )
  .blend(osc(12, 0.08, 2.5).modulate(noise(2, 0.2), 0.08), 0.45)
  .modulate(noise(1.5, 0.1), 0.06)
  .blend(src(o0).hue(() => 0.003 + amp() * 0.006).colorama(() => 0.002 + mid() * 0.004), 0.82)
  .saturate(() => 1.3 + low() * 0.4)
  .contrast(() => 1.03 + low() * 0.1)
  .brightness(() => 0.03 + low() * 0.04)
  .out(o0)
